import{_ as e,o as n,c as t,ai as r}from"./chunks/framework.C3VoC05s.js";const h=JSON.parse('{"title":"NJUPT-Suan-API 介绍","description":"","frontmatter":{},"headers":[],"relativePath":"suan-api/introduction.md","filePath":"suan-api/introduction.md"}'),i={name:"suan-api/introduction.md"};function o(s,a,P,p,l,c){return n(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="njupt-suan-api-介绍" tabindex="-1">NJUPT-Suan-API 介绍 <a class="header-anchor" href="#njupt-suan-api-介绍" aria-label="Permalink to “NJUPT-Suan-API 介绍”">​</a></h1><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to “这是什么”">​</a></h2><p>NJUPT 是 <strong>南京邮电大学</strong> 或者 <strong>Nanjing University of Posts and Telecommunications</strong> 的意思。</p><p>Suan 是本项目的代号，芒果酸或者芒果酸酸。</p><p>API 是这个东西的工作，作为 API，以及 MCP。</p><p>MCP 是模型上下文协议，用于给 LLM 提供可供调用的工具。</p><h2 id="特别说明" tabindex="-1">特别说明 <a class="header-anchor" href="#特别说明" aria-label="Permalink to “特别说明”">​</a></h2><p>由于在网络上缺少与南京邮电大学相关的 Web API，已有的项目（<a href="https://github.com/gaoliang/NJUPT-API" target="_blank" rel="noreferrer">NJUPT-API</a>）也已经年久失修， 芒果帆帆复刻这些 API 的过程也并不顺利。</p><p>经过芒果帆帆的社工活动可得，我邮并不对外提供查询课表、跑操次数等数据的接口，因此 NJUPT-Suan-API 不得不另辟蹊径来获得课表数据。</p><h2 id="技术路线" tabindex="-1">技术路线 <a class="header-anchor" href="#技术路线" aria-label="Permalink to “技术路线”">​</a></h2><p>NJUPT-Suan-API 使用 Python 实现了 API 和 MCP 后端，主要使用了 FastAPI 和 FastMCP，所有功能一式两份在 API 和 MCP 中分别提供。</p><p>另外提供 WebUI 管理面板用来便于管理。管理面板使用 Vue 设计。出于一些考量，管理面板不是可选的模块。</p>',12)])])}const u=e(i,[["render",o]]);export{h as __pageData,u as default};
